const item = $input.first();
const raw = item.json || {};
const body = raw.body && typeof raw.body === 'object' ? raw.body : raw;
const topic = (body.topic || body.message || '').toString().trim();
if (!topic || topic.length < 2) {
  throw new Error('Campo "topic" obrigatório. Envie um tópico de pesquisa.');
}
const period = (body.period || '12').toString();
const sources = (body.sources || '').toString();
return [{ json: { topic, period, sources } }];

const parseData = $('Parse Request').first().json;
const topic = parseData.topic || 'Pesquisa';
const serperItem = $input.first();
const serperData = serperItem.json || {};
const organic = Array.isArray(serperData.organic) ? serperData.organic : [];

const title = 'Pesquisa: ' + topic.substring(0, 60);
let reasoning = 'Pesquisa executada sobre "' + topic + '". Fontes: Serper (web). ';

const rows = [['Fonte', 'Título', 'Resumo', 'Link']];
for (let i = 0; i < Math.min(organic.length, 20); i++) {
  const o = organic[i];
  rows.push([
    'Serper',
    (o.title || '').substring(0, 100),
    (o.snippet || '').substring(0, 200),
    (o.link || '').substring(0, 150)
  ]);
}
if (organic.length === 0) {
  rows.push(['N/A', 'Nenhum resultado encontrado', '', '']);
}

reasoning += organic.length + ' resultados consolidados.';

return [{ json: { title, reasoning, rows } }];

const struct = $('Estruturar Dados').first().json;
const createOut = $input.first().json;
const spreadsheetId = createOut.spreadsheetId || createOut.id;
const rows = struct.rows || [];
const items = [];
for (let i = 0; i < rows.length; i++) {
  items.push({ json: { spreadsheetId, col1: rows[i][0] || '', col2: rows[i][1] || '', col3: rows[i][2] || '', col4: rows[i][3] || '' } });
}
return items.length > 0 ? items : [{ json: { spreadsheetId, col1: 'Fonte', col2: 'Título', col3: 'Resumo', col4: 'Link' } }];

const struct = $('Estruturar Dados').first().json;
let createOutput = null;
try {
  createOutput = $('Criar Planilha').first().json;
} catch (e) {}

const spreadsheetId = createOutput?.spreadsheetId || createOutput?.id;
let sheetsUrl = null;
if (spreadsheetId) {
  sheetsUrl = 'https://docs.google.com/spreadsheets/d/' + spreadsheetId + '/edit';
}

return [{ json: {
  sheets_url: sheetsUrl,
  report_url: sheetsUrl,
  report_title: struct.title,
  reasoning: struct.reasoning || '',
  error: !sheetsUrl ? 'Planilha não criada. Configure credenciais Google Sheets no n8n.' : null
}}];
